<script setup lang="ts">import{useI18n}from'vue-i18n';defineProps<{title:string;text:string;empty:string}>();defineEmits<{copy:[text:string]}>();const{t}=useI18n()</script><template><section class="monitor-output"><header class="section-heading"><h2>{{title}}</h2><button :disabled="!text" @click="$emit('copy',text)">{{t('monitor.copy')}}</button></header><pre>{{text||empty}}</pre></section></template>
